#include <bits/stdc++.h>
using namespace std;

class DisjointSet {
    /* To store the ranks, parents and 
    sizes of different set of vertices */
    vector<int> rank, parent, size;

public:

    // Constructor
    DisjointSet(int n) {
        rank.resize(n + 1, 0);
        parent.resize(n + 1);
        size.resize(n + 1);
        for (int i = 0; i <= n; i++) {
            parent[i] = i;
            size[i] = 1;
        }
    }

    // Function to find ultimate parent
    int findUPar(int node) {
        if (node == parent[node])
            return node;
        return parent[node] = findUPar(parent[node]);
    }

    // Function to implement union by rank
    void unionByRank(int u, int v) {
        int ulp_u = findUPar(u);
        int ulp_v = findUPar(v);
        if (ulp_u == ulp_v) return;
        if (rank[ulp_u] < rank[ulp_v]) {
            parent[ulp_u] = ulp_v;
        }
        else if (rank[ulp_v] < rank[ulp_u]) {
            parent[ulp_v] = ulp_u;
        }
        else {
            parent[ulp_v] = ulp_u;
            rank[ulp_u]++;
        }
    }

    // Function to implement union by size
    void unionBySize(int u, int v) {
        int ulp_u = findUPar(u);
        int ulp_v = findUPar(v);
        if (ulp_u == ulp_v) return;
        if (size[ulp_u] < size[ulp_v]) {
            parent[ulp_u] = ulp_v;
            size[ulp_v] += size[ulp_u];
        }
        else {
            parent[ulp_v] = ulp_u;
            size[ulp_u] += size[ulp_v];
        }
    }
};

// Solution class
class Solution{
public:

    // Function to get the sum of weights of edges in MST
    int spanningTree(int V, vector<vector<int>> adj[]) {

        // To store the edges
        vector<pair<int, pair<int, int>>> edges;

        // Getting all edges from adjacency list
        for (int i = 0; i < V; i++) {
            for (auto it : adj[i]) {
                int v = it[0]; // Node v
                int wt = it[1]; // edge weight
                int u = i; // Node u
                edges.push_back({wt, {u, v}});
            }
        }

        // Creating a disjoint set of V vertices
        DisjointSet ds(V);

        // Sorting the edges based on their weights
        sort(edges.begin(), edges.end());

        // To store the sum of edges in MST
        int sum = 0;

        // Iterate on the edges
        for (auto it : edges) {
            int wt = it.first; // edge weight
            int u = it.second.first; // First node
            int v = it.second.second; // Second node

            // Join the nodes if not in the same set 
            if (ds.findUPar(u) != ds.findUPar(v)) {

                // Update the sum of edges in MST
                sum += wt;

                // Unite the nodes 
                ds.unionBySize(u, v);
            }
        }

        // Return the computed sum
        return sum;
    }
};


int main() {
    int V = 4;
    vector<vector<int>> edges = {
        {0, 1, 1},
        {1, 2, 2},
        {2, 3, 3},
        {0, 3, 4}
    };

    // Forming the adjacency list from edges
    vector<vector<int>> adj[4];
    for(auto it : edges) {
        int u = it[0];
        int v = it[1];
        int wt = it[2];

        adj[u].push_back({v, wt});
        adj[v].push_back({u, wt});
    }

    // Creating instance of Solution class
    Solution sol;

    /* Function call to get the sum 
    of weights of edges in MST */
    int ans = sol.spanningTree(V, adj);

    cout << "The sum of weights of edges in MST is: " << ans;

    return 0;
}

